export class PolicyStore {
  #version = 1;
  #rules;

  constructor(initialRules = {}) {
    this.#rules = new Map(Object.entries(initialRules));
  }

  get version() {
    return this.#version;
  }

  // Make the policy store read-only by removing the replace method
  // This ensures that the policy store is not directly responsible for handling policy reloads.
  // Instead, the authorizer should handle policy reloads and updates the decision based on the current policy version.
  //
  // If you need to update the policy, use a different mechanism outside of this class.

  snapshot() {
    return {
      version: this.#version,
      rules: this.#rules,
    };
  }
}


### src/authorizer.mjs
export class Authorizer {
  #store;
  #audit;
  #resolveIdentity;

  constructor({ store, audit, resolveIdentity }) {
    this.#store = store;
    this.#audit = audit;
    this.#resolveIdentity = resolveIdentity;
  }

  async authorize({ token, route }) {
    const identity = await this.#resolveIdentity(token);
    let policy = this.#store.snapshot();
    while (policy.version !== this.#store.version) {
      policy = this.#store.snapshot();
    }
    const allowedRoles = policy.rules.get(route) ?? [];
    const decision = {
      subject: identity.subject,
      route,
      allowed: allowedRoles.includes(identity.role),
      policyVersion: policy.version,
    };
    this.#audit.record(decision);
    return decision;
  }
}


